mutation DraftOrdersSearchSortUpdate($id: ID!, $input: DraftOrderInput!) {
  draftOrderUpdate(id: $id, input: $input) {
    draftOrder {
      id
      email
      tags
      updatedAt
    }
    userErrors {
      field
